const fs = require('fs');
const watchDir = '/home/node/watch';

// Find all date prefixes that have both a chat and transcript file
const files = fs.readdirSync(watchDir);
const dateMap = {};
for (const f of files) {
  const m = f.match(/^(\d{4}-\d{2}-\d{2})/);
  if (!m) continue;
  const date = m[1];
  if (!dateMap[date]) dateMap[date] = {};
  if (f.includes('-zoom-chat') && f.endsWith('.txt')) dateMap[date].chat = f;
  if (f.includes('-transcript') && f.endsWith('.txt')) dateMap[date].transcript = f;
}

// Pick the most recent date that has both files
const complete = Object.entries(dateMap)
  .filter(([, v]) => v.chat && v.transcript)
  .sort(([a], [b]) => b.localeCompare(a));

if (complete.length === 0) {
  throw new Error('No complete file pairs found in watch directory (need both YYYY-MM-DD-zoom-chat.txt and YYYY-MM-DD-transcript.txt)');
}

const [datePrefix, { chat, transcript }] = complete[0];
const chatFile = `${watchDir}/${chat}`;
const transcriptFile = `${watchDir}/${transcript}`;

const chatText = fs.readFileSync(chatFile, 'utf8');
const transcriptText = fs.readFileSync(transcriptFile, 'utf8');

return {
  json: {
    datePrefix,
    chatText,
    transcriptText,
    chatFile,
    transcriptFile
  }
};

